#!/usr/bin/env python3
import os, torch, json
from datasets import Dataset

HF_TOKEN = os.environ.get("HF_TOKEN", "")
BASE_MODEL = "cognitivecomputations/dolphin-2.9-llama3-8b"
OUTPUT_REPO = "RsCodebot/myauntiescuz-general"
DATASET_PATH = "/root/general_dataset.jsonl"
MAX_SEQ_LEN = 2048
LORA_RANK = 32
LORA_ALPHA = 64
BATCH_SIZE = 2
GRAD_ACCUM = 4
EPOCHS = 3
LR = 2e-4

def load_dataset_local(path):
    records = []
    with open(path) as f:
        for line in f:
            line = line.strip()
            if line:
                records.append(json.loads(line))
    return records

def format_conversation(record):
    text = ""
    for msg in record["messages"]:
        role, content = msg["role"], msg["content"]
        if role == "system":
            text += f"<|im_start|>system\n{content}<|im_end|>\n"
        elif role == "user":
            text += f"<|im_start|>user\n{content}<|im_end|>\n"
        elif role == "assistant":
            text += f"<|im_start|>assistant\n{content}<|im_end|>\n"
    return text

def main():
    print("=" * 60)
    print("MYAUNTIESCUZ-GENERAL TRAINING")
    print("=" * 60)

    from unsloth import FastLanguageModel
    from trl import SFTTrainer, SFTConfig
    from huggingface_hub import login

    login(token=HF_TOKEN)

    print("\nLoading base model...")
    model, tokenizer = FastLanguageModel.from_pretrained(
        model_name=BASE_MODEL,
        max_seq_length=MAX_SEQ_LEN,
        dtype=None,
        load_in_4bit=True,
    )

    model = FastLanguageModel.get_peft_model(
        model,
        r=LORA_RANK,
        target_modules=["q_proj", "k_proj", "v_proj", "o_proj",
                        "gate_proj", "up_proj", "down_proj"],
        lora_alpha=LORA_ALPHA,
        lora_dropout=0.05,
        bias="none",
        use_gradient_checkpointing="unsloth",
        random_state=42,
    )

    print("\nLoading dataset...")
    raw_data = load_dataset_local(DATASET_PATH)
    formatted = [{"text": format_conversation(r)} for r in raw_data]
    dataset = Dataset.from_list(formatted)
    print(f"Training pairs: {len(formatted)}")

    training_args = SFTConfig(
        output_dir="/root/myauntiescuz-general-output",
        num_train_epochs=EPOCHS,
        per_device_train_batch_size=BATCH_SIZE,
        gradient_accumulation_steps=GRAD_ACCUM,
        learning_rate=LR,
        fp16=not torch.cuda.is_bf16_supported(),
        bf16=torch.cuda.is_bf16_supported(),
        logging_steps=5,
        save_steps=50,
        warmup_ratio=0.05,
        lr_scheduler_type="cosine",
        optim="adamw_8bit",
        weight_decay=0.01,
        report_to="none",
        seed=42,
        dataset_text_field="text",
        max_seq_length=MAX_SEQ_LEN,
    )

    trainer = SFTTrainer(
        model=model,
        processing_class=tokenizer,
        train_dataset=dataset,
        args=training_args,
    )

    print("\nStarting training...")
    trainer.train()

    print("\nSaving and pushing...")
    model.save_pretrained("/root/myauntiescuz-general-lora")
    tokenizer.save_pretrained("/root/myauntiescuz-general-lora")
    model.push_to_hub(OUTPUT_REPO, token=HF_TOKEN, private=True)
    tokenizer.push_to_hub(OUTPUT_REPO, token=HF_TOKEN, private=True)

    print("\n" + "=" * 60)
    print("MYAUNTIESCUZ-GENERAL UPLOAD COMPLETE")
    print(f"https://huggingface.co/{OUTPUT_REPO}")
    print("=" * 60)

if __name__ == "__main__":
    main()
PYEOF
